import{_ as e,o as a,c as l,a0 as o}from"./chunks/framework.CWk8AOcY.js";const u=JSON.parse('{"title":"模板概览 (Templates)","description":"","frontmatter":{},"headers":[],"relativePath":"zh/guide/templates.md","filePath":"zh/guide/templates.md"}'),r={name:"zh/guide/templates.md"};function i(s,t,n,p,m,h){return a(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="模板概览-templates" tabindex="-1">模板概览 (Templates) <a class="header-anchor" href="#模板概览-templates" aria-label="Permalink to &quot;模板概览 (Templates)&quot;">​</a></h1><p>Template（模板）是 Cube-Sandbox 创建实例的基础镜像和配置快照。本页介绍模板的<strong>概念与生命周期</strong>。</p><ul><li>使用 CLI 创建、监控、查询或删除模板，请参阅<a href="./tutorials/template-from-image.html">从 OCI 镜像制作模板</a>。</li><li>查看模板状态并预览最终请求，请参阅 <a href="./template-inspection-and-preview.html">模板检查与请求预览</a>。</li></ul><h2 id="模板生命周期-三步制作流程" tabindex="-1">模板生命周期 (三步制作流程) <a class="header-anchor" href="#模板生命周期-三步制作流程" aria-label="Permalink to &quot;模板生命周期 (三步制作流程)&quot;">​</a></h2><ol><li><p><strong>Init (初始化构建)</strong> 基于基础镜像（如 Ubuntu）和 Dockerfile，使用 Buildkit 等构建引擎，打包出满足沙箱运行需求的 rootfs 文件系统。</p></li><li><p><strong>Boot &amp; Snapshot (冷启动与快照)</strong> 将初始化的 rootfs 放入 MicroVM 中冷启动。等待系统和语言环境（如 Python、Node）完全加载后，对此时的内存和状态打下快照 (Snapshot)。</p></li><li><p><strong>Deploy (注册与发布)</strong> 将打包好的 Rootfs 和 Snapshot 文件注册到系统中，成为一个可用的 Template。后续即可通过该 Template 实现沙箱的 <strong>热启动 (Hot Start)</strong>，实现极速启动。</p></li></ol><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./tutorials/template-from-image.html">从 OCI 镜像制作模板</a> — 完整的 CLI 指南，包括探针配置、进度监控和故障排查。</li><li><a href="./template-inspection-and-preview.html">模板检查与请求预览</a> — 如何查看模板状态并预览最终生效的请求。</li></ul>',7)])])}const c=e(r,[["render",i]]);export{u as __pageData,c as default};
